package redis

import (
	"context"
	"encoding/json"
	"fmt"
	"time"

	"github.com/redis/go-redis/v9"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

type RedisStore struct {
	client           *redis.Client
	expiryZSet       string
	lastActivityZSet string
	sessionPrefix    string
}

func NewRedisStore(addr, password string) (*RedisStore, error) {
	client := redis.NewClient(&redis.Options{
		Addr:     addr,
		Password: password,
		DB:       0,
	})

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := client.Ping(ctx).Err(); err != nil {
		return nil, fmt.Errorf("failed to connect to redis: %w", err)
	}

	return &RedisStore{
		client:           client,
		expiryZSet:       "session:expiry",
		lastActivityZSet: "session:last_activity",
		sessionPrefix:    "session:",
	}, nil
}

func (r *RedisStore) Ping(ctx context.Context) error {
	return r.client.Ping(ctx).Err()
}

func (r *RedisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := r.sessionPrefix + sessionID
	data, err := r.client.Get(ctx, key).Bytes()
	if err != nil {
		if err == redis.Nil {
			return nil, store.ErrNotFound
		}
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal(data, &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (r *RedisStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	key := r.sessionPrefix + sandbox.SessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	expiryTime := sandbox.CreatedAt.Add(24 * time.Hour)
	pipe := r.client.Pipeline()
	pipe.SetNX(ctx, key, data, 24*time.Hour)
	pipe.ZAdd(ctx, r.expiryZSet, redis.Z{Score: float64(expiryTime.Unix()), Member: sandbox.SessionID})
	pipe.ZAdd(ctx, r.lastActivityZSet, redis.Z{Score: float64(sandbox.LastActivity.Unix()), Member: sandbox.SessionID})

	_, err = pipe.Exec(ctx)
	return err
}

func (r *RedisStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	key := r.sessionPrefix + sandbox.SessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	result, err := r.client.Set(ctx, key, data, 24*time.Hour).Result()
	if result == "OK" {
		return nil
	}
	return err
}

func (r *RedisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := r.sessionPrefix + sessionID
	pipe := r.client.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, r.expiryZSet, sessionID)
	pipe.ZRem(ctx, r.lastActivityZSet, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

func (r *RedisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	members, err := r.client.ZRangeByScore(ctx, r.expiryZSet, &redis.ZRangeBy{
		Min:   "0",
		Max:   fmt.Sprintf("%d", before.Unix()),
		Count: limit,
	}).Result()
	if err != nil {
		return nil, err
	}

	return r.getSandboxesByIDs(ctx, members)
}

func (r *RedisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	members, err := r.client.ZRangeByScore(ctx, r.lastActivityZSet, &redis.ZRangeBy{
		Min:   "0",
		Max:   fmt.Sprintf("%d", before.Unix()),
		Count: limit,
	}).Result()
	if err != nil {
		return nil, err
	}

	return r.getSandboxesByIDs(ctx, members)
}

func (r *RedisStore) getSandboxesByIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	var sandboxes []*types.SandboxInfo
	for _, id := range sessionIDs {
		sandbox, err := r.GetSandboxBySessionID(ctx, id)
		if err != nil {
			if err == store.ErrNotFound {
				continue
			}
			return nil, err
		}
		sandboxes = append(sandboxes, sandbox)
	}
	return sandboxes, nil
}

func (r *RedisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	return r.client.ZAdd(ctx, r.lastActivityZSet, redis.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	}).Err()
}

func (r *RedisStore) Close() error {
	return r.client.Close()
}

