		return err
	}

	expiryTime := sandbox.CreatedAt.Add(24 * time.Hour)
	pipe := v.client.Pipeline()
	pipe.SetNX(ctx, key, data, 24*time.Hour)
	pipe.ZAdd(ctx, v.expiryZSet, valkey.Z{Score: float64(expiryTime.Unix()), Member: sandbox.SessionID})
	pipe.ZAdd(ctx, v.lastActivityZSet, valkey.Z{Score: float64(sandbox.LastActivity.Unix()), Member: sandbox.SessionID})

